INSERT INTO neighborhood_profiles (city, neighborhood, narrative, best_for) VALUES
('Jerusalem', 'Abu Tor', 'A mixed, multicultural neighborhood perched on a hillside between the Old City and North Talpiot, Abu Tor is genuinely one of Jerusalem''s most architecturally striking and underappreciated pockets — old Arab-style stone houses with arched ceilings, wrap-around gardens, and panoramic views of the city, sitting quietly between the German Colony and East Talpiot. The housing stock leans toward low-rise, character-filled buildings on streets like Oved and Nakhshon, with a handful of freestanding cottages and small apartment buildings; it''s within walking distance of the Old City, the Talpiot commercial strip, and major hotels. The neighborhood is majority Arab and Jewish mixed, which makes it genuinely diverse but also means this isn''t a ready-made Anglo community — most daily life requires functional Hebrew, and you should visit before buying to understand the specific block you''re considering.', 'Buyers who want authentic Jerusalem character and panoramic views at prices well below the German Colony, and who are comfortable navigating a non-Anglo street environment.'),
('Jerusalem', 'Armon HaNatziv', 'Armon HaNatziv is best known for the Haas Sherover Promenade (the Tayelet) — one of Jerusalem''s finest public spaces, with unobstructed views stretching to the Temple Mount, Judean Hills, and on clear days the Dead Sea — and the neighborhood wraps around a dramatic ridge with that view baked into everyday life. The housing is mostly mid-rise apartment buildings from the 1980s–1990s, with some newer development on streets like Elkachi, Adam, and Remba near the Arnona border; prices range from around NIS 2.6–3.2 million for a 4-room apartment, considerably less than neighboring Arnona. The neighborhood is traditionally Israeli and only now seeing a trickle of young Anglo families attracted by the views and affordability — daily life is primarily Hebrew, there are schools and clinics on-site, and Ulpan Etzion has brought some new immigrants to the area — but if you''re expecting a built-out Anglo social infrastructure, this isn''t it yet.', 'Budget-conscious Anglo couples or young families who want spectacular views and don''t mind building community from scratch.'),
('Jerusalem', 'Arnona', 'Arnona has become one of the most sought-after addresses for Anglos moving to southern Jerusalem, sitting just below Baka and the German Colony with views toward the Dead Sea and Judean Hills, and home to the U.S. Embassy and the Shai Agnon House museum — a neighborhood that punches above its weight for prestige. The housing mix runs from British Mandate-era cottages on streets like Rabeno Politi and Revadim, to newer luxury towers and spacious duplexes; new construction starts around NIS 36,000–37,000/sqm and established apartments from around NIS 27,000/sqm. The steady Anglo presence here is real — you''ll find English speakers at the makolet and in the parks — but prices have risen sharply in recent years, making Arnona no longer the "cheap alternative to Baka" it once was.', 'Established Anglo families or early-retiree olim who want proximity to Baka/German Colony with more space per shekel and a quieter residential feel.'),
('Jerusalem', 'Baka', 'Baka is one of Jerusalem''s most established Anglo hubs, the kind of neighborhood where you''ll hear English on the street without even trying — Modern Orthodox families, young couples, and career olim have built a dense community here centered on Derech Beit Lechem, Park HaMesila (the old train tracks converted to a linear park), and streets like Mordechai HaYehudi and Reuven. The housing is predominantly older Jerusalem stone buildings — many in beautiful Arab-style architecture with arched ceilings and original tiles — alongside boutique TAMA 38 projects and a handful of new developments; a renovated 4-room apartment runs NIS 4.8–6.2 million or higher. Shuls like Nitzanim anchor the community, Efrata and Pelech schools are local institutions, and the neighborhood''s proximity to Emek Refaim is a daily perk — but the price premium is very real, older buildings often lack elevators, and parking on the quieter streets is a known frustration.', 'Modern Orthodox Anglo families who want a fully built-out English-speaking community and are willing to pay the Baka premium for it.'),
('Jerusalem', 'Bayit Vegan', 'Bayit Vegan is a predominantly Haredi neighborhood in southwest Jerusalem, anchored by some of Israel''s most respected Torah institutions: Kol Torah Yeshiva, Ateret Yisrael, Yeshivat Torat Shraga, Michlalah Jerusalem College for Women, Netiv Meir high school, and Boys Town Jerusalem — making it, institutionally, one of the most densely Jewish-educated neighborhoods in the country. The housing is mostly older apartment buildings and a handful of cottages on quieter streets, adjacent to Kiryat Moshe and Givat Mordechai; Shaare Zedek Medical Center sits at the neighborhood entrance, which is a genuine practical plus for families. With roughly 22,000 residents and about half under 18, this is a high-energy, child-heavy neighborhood — it suits families deeply embedded in the Haredi or Religious Zionist world, but secular buyers or those wanting a mixed community will feel out of step here.', 'Haredi or Religious Zionist families, yeshiva families, or olim plugging into the Torah-learning world who want to be near leading institutions.')
